struct LineInfo {
  std::string filename;
  int sourceLine;
};

std::pair<std::vector<LineInfo>, std::string>
preprocess(const std::string& content)
{
  std::vector<LineInfo> lineInfo;
  std::string cleanContent;

  std::istringstream stream(content);
  std::string line;
  std::string currentFile;
  int currentLine = 0;

  while (std::getline(stream, line)) {
    // Check for line marker: # L "file" flags
    if (line.size() >= 2 && line[0] == '#') {
      std::istringstream lstream(line);
      std::string hash;
      int linenum;
      std::string filename;
      lstream >> hash;
      if (lstream >> linenum) {
        lstream >> std::ws;
        if (lstream.peek() == '"') {
          std::getline(lstream, filename, '"');
          std::getline(lstream, filename, '"');
        }
        int flags = 0;
        lstream >> flags;
        if (!filename.empty()) {
          currentFile = filename;
          currentLine = linenum;
          // For '1' (entering) or '2' (returning), update line tracking
          if (flags == 1) {
            // entering new file, reset line tracking
          }
        }
      }
      // Skip line marker, but still record line info as unmodified
      // (line markers themselves should not appear in the output)
      continue;
    }

    // Record mapping for this content line
    LineInfo info;
    info.filename = currentFile;
    info.sourceLine = currentLine;
    lineInfo.push_back(info);
    if (!currentFile.empty())
      currentLine++;

    cleanContent += line + "\n";
  }

  return {lineInfo, cleanContent};
}

void
print_token(const antlr4::Token* token,
            const std::vector<LineInfo>& lineInfo,
            std::ofstream& outFile,
            const antlr4::Lexer& lexer,
            const std::string& input)
{
  auto& vocabulary = lexer.getVocabulary();

  std::string tokenTypeName =
    std::string(vocabulary.getSymbolicName(token->getType()));

  if (tokenTypeName.empty())
    tokenTypeName = "<UNKNOWN>";

  auto it = tokenTypeMapping.find(tokenTypeName);
  if (it != tokenTypeMapping.end()) {
    tokenTypeName = it->second;
  }

  size_t antlrLine = token->getLine();
  size_t antlrCol = token->getCharPositionInLine();

  // Build location info
  std::string locInfo;
  if (antlrLine > 0 && antlrLine <= lineInfo.size()) {
    const auto& info = lineInfo[antlrLine - 1];
    locInfo = " Loc=<" + info.filename + ":" +
              std::to_string(info.sourceLine) + ":" +
              std::to_string(antlrCol + 1) + ">";
  } else if (tokenTypeName == "eof" && !lineInfo.empty()) {
    // EOF: use last line info but column + 1
    const auto& info = lineInfo.back();
    locInfo = " Loc=<" + info.filename + ":" +
              std::to_string(info.sourceLine) + ":" +
              std::to_string(antlrCol + 1) + ">";
  } else {
    locInfo = " Loc=<0:0>";
