   102	
   103	static int
   104	eval_arrlen(Expr* expr)
   105	{
   106	  if (auto p = expr->dcst<IntegerLiteral>())
   107	    return p->val;
   108	
   109	  if (auto p = expr->dcst<DeclRefExpr>()) {
   110	    if (p->decl == nullptr)
   111	      ABORT();
   112	
   113	    auto var = p->decl->dcst<VarDecl>();
   114	    if (!var || !var->type->qual.const_)
   115	      ABORT(); // 数组长度必须是编译期常量
   116	
   117	    switch (var->type->spec) {
   118	      case Type::Spec::kChar:
   119	      case Type::Spec::kInt:
   120	      case Type::Spec::kLong:
   121	      case Type::Spec::kLongLong:
   122	        return eval_arrlen(var->init);
   123	
   124	      default:
   125	        ABORT(); // 长度表达式必须是数值类型
   126	    }
   127	  }
   128	
   129	  if (auto p = expr->dcst<UnaryExpr>()) {
   130	    auto sub = eval_arrlen(p->sub);
   131	
   132	    switch (p->op) {
   133	      case UnaryExpr::kPos:
   134	        return sub;
   135	
   136	      case UnaryExpr::kNeg:
   137	        return -sub;
   138	
   139	      default:
   140	        ABORT();
   141	    }
   142	  }
   143	
   144	  if (auto p = expr->dcst<BinaryExpr>()) {
   145	    auto lft = eval_arrlen(p->lft);
   146	    auto rht = eval_arrlen(p->rht);
   147	
   148	    switch (p->op) {
   149	      case BinaryExpr::kAdd:
   150	        return lft + rht;
   151	
   152	      case BinaryExpr::kSub:
   153	        return lft - rht;
   154	
   155	      default:
   156	        ABORT();
   157	    }
   158	  }
   159	
   160	  if (auto p = expr->dcst<InitListExpr>()) {
   161	    if (p->list.empty())
   162	      return 0;
   163	    return eval_arrlen(p->list[0]);
   164	  }
   165	
   166	  ABORT();
   167	}
