   169	std::pair<TypeExpr*, std::string>
   170	Ast2Asg::operator()(ast::DirectDeclaratorContext* ctx, TypeExpr* sub)
   171	{
   172	  if (auto p = ctx->Identifier())
   173	    return { sub, p->getText() };
   174	
   175	  if (ctx->LeftBracket()) {
   176	    auto arrayType = make<ArrayType>();
   177	    arrayType->sub = sub;
   178	
   179	    if (auto p = ctx->assignmentExpression())
   180	      arrayType->len = eval_arrlen(self(p));
   181	    else
   182	      arrayType->len = ArrayType::kUnLen;
   183	
   184	    return self(ctx->directDeclarator(), arrayType);
   185	  }
   186	
   187	  ABORT();
   188	}
