   194	Expr*
   195	Ast2Asg::operator()(ast::ExpressionContext* ctx)
   196	{
   197	  auto list = ctx->assignmentExpression();
   198	  Expr* ret = self(list[0]);
   199	
   200	  for (unsigned i = 1; i < list.size(); ++i) {
   201	    auto node = make<BinaryExpr>();
   202	    node->op = node->kComma;
   203	    node->lft = ret;
   204	    node->rht = self(list[i]);
   205	    ret = node;
   206	  }
   207	
   208	  return ret;
   209	}
