   211	Expr*
   212	Ast2Asg::operator()(ast::AssignmentExpressionContext* ctx)
   213	{
   214	  if (auto p = ctx->additiveExpression())
   215	    return self(p);
   216	
   217	  auto ret = make<BinaryExpr>();
   218	  ret->op = ret->kAssign;
   219	  ret->lft = self(ctx->unaryExpression());
   220	  ret->rht = self(ctx->assignmentExpression());
   221	  return ret;
   222	}
   223	Expr*
   224	Ast2Asg::operator()(ast::AdditiveExpressionContext* ctx)
   225	{
   226	  auto children = ctx->children;
   227	  Expr* ret = self(dynamic_cast<ast::UnaryExpressionContext*>(children[0]));
   228	
   229	  for (unsigned i = 1; i < children.size(); ++i) {
   230	    auto node = make<BinaryExpr>();
   231	
   232	    auto token = dynamic_cast<antlr4::tree::TerminalNode*>(children[i])
   233	                   ->getSymbol()
   234	                   ->getType();
   235	    switch (token) {
   236	      case ast::Plus:
   237	        node->op = node->kAdd;
   238	        break;
   239	
   240	      case ast::Minus:
   241	        node->op = node->kSub;
   242	        break;
   243	
   244	      default:
   245	        ABORT();
   246	    }
   247	
   248	    node->lft = ret;
   249	    node->rht = self(dynamic_cast<ast::UnaryExpressionContext*>(children[++i]));
   250	    ret = node;
   251	  }
   252	
   253	  return ret;
   254	}
