   293	Expr*
   294	Ast2Asg::operator()(ast::PrimaryExpressionContext* ctx)
   295	{
   296	
   297	  if (auto p = ctx->Identifier()) {
   298	    auto name = p->getText();
   299	    auto ret = make<DeclRefExpr>();
   300	    ret->decl = mSymtbl->resolve(name);
   301	    return ret;
   302	  }
   303	
   304	  if (auto p = ctx->Constant()) {
   305	    auto text = p->getText();
   306	
   307	    auto ret = make<IntegerLiteral>();
   308	
   309	    ASSERT(!text.empty());
   310	    if (text[0] != '0')
   311	      ret->val = std::stoll(text);
   312	
   313	    else if (text.size() == 1)
   314	      ret->val = 0;
   315	
   316	    else if (text[1] == 'x' || text[1] == 'X')
   317	      ret->val = std::stoll(text.substr(2), nullptr, 16);
   318	
   319	    else
   320	      ret->val = std::stoll(text.substr(1), nullptr, 8);
   321	
   322	    return ret;
   323	  }
   324	
   325	  ABORT();
   326	}
