   427	std::vector<Decl*>
   428	Ast2Asg::operator()(ast::DeclarationContext* ctx)
   429	{
   430	  std::vector<Decl*> ret;
   431	
   432	  auto specs = self(ctx->declarationSpecifiers());
   433	
   434	  if (auto p = ctx->initDeclaratorList()) {
   435	    for (auto&& j : p->initDeclarator())
   436	      ret.push_back(self(j, specs));
   437	  }
