    node->rht = self(dynamic_cast<ast::EqualityExpressionContext*>(children[++i]));
    ret = node;
  }
  return ret;
}

Expr*
Ast2Asg::operator()(ast::ExclusiveOrExpressionContext* ctx)
{
  auto children = ctx->children;
  Expr* ret = self(dynamic_cast<ast::AndExpressionContext*>(children[0]));
  for (unsigned i = 1; i < children.size(); i += 2) {
    auto node = make<BinaryExpr>();
    node->op = node->kINVALID;
    node->lft = ret;
    node->rht = self(dynamic_cast<ast::AndExpressionContext*>(children[i + 1]));
    ret = node;
  }
  return ret;
}

Expr*
Ast2Asg::operator()(ast::InclusiveOrExpressionContext* ctx)
{
  auto children = ctx->children;
  Expr* ret = self(dynamic_cast<ast::ExclusiveOrExpressionContext*>(children[0]));
  for (unsigned i = 1; i < children.size(); i += 2) {
    auto node = make<BinaryExpr>();
    node->op = node->kINVALID;
    node->lft = ret;
    node->rht = self(dynamic_cast<ast::ExclusiveOrExpressionContext*>(children[i + 1]));
    ret = node;
  }
  return ret;
}

Expr*
Ast2Asg::operator()(ast::LogicalAndExpressionContext* ctx)
{
  auto children = ctx->children;
  Expr* ret = self(dynamic_cast<ast::InclusiveOrExpressionContext*OrExpressionContext*>(children[0]));
  for (unsigned i = 1; i < children.size(); ++i) {
    auto node = make<BinaryExpr>();
    node->op = node->kAnd;
    node->lft = ret;
    node->rht = self(dynamic_cast<ast::InclusiveOrExpressionContext*>(children[++i]));
    ret = node;
  }
  return ret;
}

Expr*
Ast2Asg::operator()(ast::LogicalOrExpressionContext* ctx)
{
  auto children = ctx->children;
  Expr* ret = self(dynamic_cast<ast::LogicalAndExpressionContext*>(children[0]));
  for (unsigned i = 1; i < children.size(); ++i) {
    auto node = make<BinaryExpr>();
    node->op = node->kOr;
    node->lft = ret;
    node->rht = self(dynamic_cast<ast::LogicalAndExpressionContext*>(children[++i]));
    ret = node;
  }
  return ret;
