#include "Ast2Asg.hpp"
#include <unordered_map>

#define self (*this)

namespace asg {

// 符号表，保存当前作用域的所有声明
struct Ast2Asg::Symtbl : public std::unordered_map<std::string, Decl*>
{
  Ast2Asg& m;
  Symtbl* mPrev;

  Symtbl(Ast2Asg& m)
    : m(m)
    , mPrev(m.mSymtbl)
  {
    m.mSymtbl = this;
  }

  ~Symtbl() { m.mSymtbl = mPrev; }

  Decl* resolve(const std::string& name);
};

Decl*
Ast2Asg::Symtbl::resolve(const std::string& name)
{
  auto iter = find(name);
  if (iter != end())
    return iter->second;
  ASSERT(mPrev != nullptr); // 标识符未定义
  return mPrev->resolve(name);
}

TranslationUnit*
Ast2Asg::operator()(ast::TranslationUnitContext* ctx)
{
  auto ret = make<asg::TranslationUnit>();
  if (ctx == nullptr)
    return ret;

  Symtbl localDecls(self);

  for (auto&& i : ctx->externalDeclaration()) {
    if (auto p = i->declaration()) {
      auto decls = self(p);
      ret->decls.insert(ret->decls.end(),
                        std::make_move_iterator(decls.begin()),
                        std::make_move_iterator(decls.end()));
    }

    else if (auto p = i->functionDefinition()) {
      auto funcDecl = self(p);
      ret->decls.push_back(funcDecl);

      // 添加到声明表
      localDecls[funcDecl->name] = funcDecl;
    }

    else
      ABORT();
  }

  return ret;
}

//==============================================================================
// 类型
//==============================================================================

Ast2Asg::SpecQual
Ast2Asg::operator()(ast::DeclarationSpecifiersContext* ctx)
{
  SpecQual ret = { Type::Spec::kINVALID, Type::Qual() };

  for (auto&& i : ctx->declarationSpecifier()) {
    if (auto p = i->typeSpecifier()) {
      if (ret.first == Type::Spec::kINVALID) {
        if (p->Int())
          ret.first = Type::Spec::kInt;
        else
          ABORT(); // 未知的类型说明符
      }

      else
        ABORT(); // 未知的类型说明符
    }

    else
      ABORT();
  }

  return ret;
}

std::pair<TypeExpr*, std::string>
Ast2Asg::operator()(ast::DeclaratorContext* ctx, TypeExpr* sub)
{
  return self(ctx->directDeclarator(), sub);
}

static int
eval_arrlen(Expr* expr)
{
  if (auto p = expr->dcst<IntegerLiteral>())
    return p->val;

  if (auto p = expr->dcst<DeclRefExpr>()) {
    if (p->decl == nullptr)
      ABORT();

    auto var = p->decl->dcst<VarDecl>();
    if (!var || !var->type->qual.const_)
      ABORT(); // 数组长度必须是编译期常量

    switch (var->type->spec) {
      case Type::Spec::kChar:
      case Type::Spec::kInt:
      case Type::Spec::kLong:
      case Type::Spec::kLongLong:
        return eval_arrlen(var->init);

      default:
        ABORT(); // 长度表达式必须是数值类型
    }
  }

  if (auto p = expr->dcst<UnaryExpr>()) {
    auto sub = eval_arrlen(p->sub);

    switch (p->op) {
      case UnaryExpr::kPos:
        return sub;

      case UnaryExpr::kNeg:
        return -sub;

      default:
        ABORT();
    }
  }

  if (auto p = expr->dcst<BinaryExpr>()) {
    auto lft = eval_arrlen(p->lft);
    auto rht = eval_arrlen(p->rht);

    switch (p->op) {
      case BinaryExpr::kAdd:
        return lft + rht;

      case BinaryExpr::kSub:
        return lft - rht;

      default:
        ABORT();
    }
  }

  if (auto p = expr->dcst<InitListExpr>()) {
    if (p->list.empty())
      return 0;
    return eval_arrlen(p->list[0]);
  }

  ABORT();
}

std::pair<TypeExpr*, std::string>
Ast2Asg::operator()(ast::DirectDeclaratorContext* ctx, TypeExpr* sub)
{
  if (auto p = ctx->Identifier())
    return { sub, p->getText() };

  if (ctx->LeftBracket()) {
    auto arrayType = make<ArrayType>();
    arrayType->sub = sub;

    if (auto p = ctx->assignmentExpression())
      arrayType->len = eval_arrlen(self(p));
    else
      arrayType->len = ArrayType::kUnLen;

    return self(ctx->directDeclarator(), arrayType);
  }

  ABORT();
}

//==============================================================================
// 表达式
//==============================================================================

Expr*
Ast2Asg::operator()(ast::ExpressionContext* ctx)
{
  auto list = ctx->assignmentExpression();
  Expr* ret = self(list[0]);

  for (unsigned i = 1; i < list.size(); ++i) {
    auto node = make<BinaryExpr>();
    node->op = node->kComma;
    node->lft = ret;
    node->rht = self(list[i]);
    ret = node;
  }

  return ret;
}

Expr*
Ast2Asg::operator()(ast::AssignmentExpressionContext* ctx)
{
  if (auto p = ctx->conditionalExpression())
    return self(p);

  auto ret = make<BinaryExpr>();
  ret->op = ret->kAssign;
  ret->lft = self(ctx->unaryExpression());
  ret->rht = self(ctx->assignmentExpression());
  return ret;
}
// Generic binary expression helper
static BinaryExpr::Op tokenToBinaryOp(size_t tokenType)
{
  switch (tokenType) {
    case ast::Plus: return BinaryExpr::kAdd;
    case ast::Minus: return BinaryExpr::kSub;
    case ast::Star: return BinaryExpr::kMul;
    case ast::Slash: return BinaryExpr::kDiv;
    case ast::Percent: return BinaryExpr::kMod;
    case ast::Less: return BinaryExpr::kLt;
    case ast::Greater: return BinaryExpr::kGt;
    case ast::LessEqual: return BinaryExpr::kLe;
    case ast::GreaterEqual: return BinaryExpr::kGe;
    case ast::EqualEqual: return BinaryExpr::kEq;
    case ast::NotEqual: return BinaryExpr::kNe;
    case ast::AndAnd: return BinaryExpr::kAnd;
    case ast::OrOr: return BinaryExpr::kOr;
    case ast::And: return BinaryExpr::kINVALID; // Bitwise AND
    case ast::Or: return BinaryExpr::kINVALID;  // Bitwise OR
    case ast::Xor: return BinaryExpr::kINVALID; // Bitwise XOR
    default: ABORT();
  }
}

template<typename Ctx>
Expr*
makeBinaryChain(Ast2Asg& ast2asg, Ctx* ctx, BinaryExpr::Op baseOp = BinaryExpr::kINVALID)
{
  auto children = ctx->children;
  auto first = dynamic_cast<decltype(ctx->castExpression(0))>(children[0]);
  (void)first;
  Expr* ret = ast2asg(dynamic_cast<decltype(ctx->castExpression(0))>(children[0]));

  for (unsigned i = 1; i; i < children.size(); ++i) {
    auto node = ast2asg.mMgr.template make<BinaryExpr>();
    auto token = dynamic_cast<antlr4::tree::TerminalNode*>(children[i])
                   ->getSymbol()->getType();
    auto op = tokenToBinaryOp(token);
    if (op == BinaryExpr::kINVALID) {
      // Handle bitwise ops
      if (token == ast::And) op = BinaryExpr::kINVALID; // We'll skip this
      else ABORT();
    }
    node->op = op;
    node->lft = ret;
    node->rht = ast2asg(dynamic_cast<decltype(ctx->castExpression(0))>(children[++i]));
    ret = node;
  }
  return ret;
}

Expr*
Ast2Asg::operator()(ast::AdditiveExpressionContext* ctx)
{
  auto children = ctx->children;
  Expr* ret = self(dynamic_cast<ast::MultiplicativeExpressionContext*>(children[0]));

  for (unsigned i = 1; i < children.size(); ++i) {
    auto node = make<BinaryExpr>();
    auto token = dynamic_cast<antlr4::tree::TerminalNode*>(children[i])->getSymbol()->getType();
    switch (token) {
      case ast::Plus: node->op = node->kAdd; break;
      case ast::Minus: node->op = node->kSub; break;
      default: ABORT();
    }
    node->lft = ret;
    node->rht = self(dynamic_cast<ast::MultiplicativeExpressionContext*>(children[++i]));
    ret = node;
  }
  return ret;
}

Expr*
Ast2Asg::operator()(ast::MultiplicativeExpressionContext* ctx)
{
  auto children = ctx->children;
  Expr* ret = self(dynamic_cast<ast::CastExpressionContext*>(children[0]));

  for (unsigned i = 1; i < children.size(); ++i) {
    auto node = make<BinaryExpr>();
    auto token = dynamic_cast<antlr4::tree::TerminalNode*>(children[i])
                   ->getSymbol()->getType();
    switch (token) {
      case ast::Star: node->op = node->kMul; break;
      case ast::Slash: node->op = node->kDiv; break;
      case ast::Percent: node->op = node->kMod; break;
      default: ABORT();
    }
    node->lft = ret;
    node->rht = self(dynamic_cast<ast::CastExpressionContext*>(children[++i]));
    ret = node;
  }
  return ret;
}

Expr*
Ast2Asg::operator()(ast::RelationalExpressionContext* ctx)
{
  auto children = ctx->children;
  Expr* ret = self(dynamic_cast<ast::ShiftExpressionContext*>(children[0]));

  for (unsigned i = 1; i < children.size(); ++i) {
    auto node = make<BinaryExpr>();
    auto token = dynamic_cast<antlr4::tree::TerminalNode*>(children[i])
                   ->getSymbol()->getType();
    switch (token) {
      case ast::Less: node->op = node->kLt; break;
      case ast::Greater: node->op = node->kGt;kGt; break;
      case ast::LessEqual: node->op = node->;kLe; break;
      case ast::GreaterEqual: node->op = node->kGe; break;
      default: ABORT();
    }
    node->lft = ret;
    node->rht = self(dynamic_cast<ast::ShiftExpressionContext*>(children[++i]));
