  auto sub = self(dynamic_cast<ast::PrimaryExpressionContext*>(children[0]));

  for (unsigned i = 1; i < children.size(); ++i) {
    auto child = children[i];
    // Function call: LeftParen ... RightParen
    if (auto paren = dynamic_cast<antlr4::tree::TerminalNode*>(child)) {
      if (paren->getSymbol()->getType() == ast::LeftParen) {
        auto call = make<CallExpr>();
        call->head = sub;
        i++;
        if (i < children.size()) {
          if (auto argCtx = dynamic_cast<ast::ArgumentExpressionListContext*>(children[i])) {
            for (auto&& expr : argCtx->assignmentExpression())
              call->args.push_back(self(expr));
