  Expr* operator()(ast::ExpressionContext* ctx);
  Expr* operator()(ast::AssignmentExpressionContext* ctx);
  Expr* operator()(ast::AdditiveExpressionContext* ctx);
  Expr* operator()(ast::UnaryExpressionContext* ctx);
