  std::vector<Decl*> operator()(ast::DeclarationContext* ctx);
  FunctionDecl* operator()(ast::FunctionDefinitionContext* ctx);
  Decl* operator()(ast::InitDeclaratorContext* ctx, SpecQual sq);

