   471	    if (!init) {
   472	      as.emitDirective("\t.zero " + std::to_string(size));
   473	      continue;
   474	    }
   475	
   476	    auto emitInit = [&](const llvm::Constant* c, auto&& emitInitRef) -> void {
   477	      if (c->isZeroValue()) {
   478	        as.emitDirective("\t.zero " + std::to_string(dl.getTypeAllocSize(c->getType())));
   479	        return;
   480	      }
