   482	        uint64_t sz = dl.getTypeAllocSize(ci->getType());
   483	        if (sz == 4) {
   484	          as.emitDirective("\t.word " + std::to_string(ci->getSExtValue()));
   485	        } else if (sz == 8) {
   486	          as.emitDirective("\t.quad " + std::to_string(ci->getSExtValue()));
   487	        } else if (sz == 1) {
   488	          as.emitDirective("\t.byte " + std::to_string(ci->getZExtValue()));
   489	        } else {
   490	          as.emitDirective("\t.zero " + std::to_string(sz));
   491	        }
   492	        return;
   493	      }
   494	      if (const auto* ca = llvm::dyn_cast<llvm::ConstantArray>(c)) {
   495	        for (unsigned i = 0; i < ca->getNumOperands(); ++i) {
   496	          emitInitRef(llvm::cast<llvm::Constant>(ca->getOperand(i)), emitInitRef);
   497	        }
   498	        return;
   499	      }
   500	      if (const auto* cda = llvm::dyn_cast<llvm::ConstantDataArray>(c)) {
   501	        for (unsigned i = 0; i < cda->getNumElements(); ++i) {
   502	          emitInitRef(cda->getElementAsConstant(i), emitInitRef);
   503	        }
   504	        return;
   505	      }
   506	      as.emitDirective("\t.zero " + std::to_string(dl.getTypeAllocSize(c->getType())));
   507	    };
   508	
   509	    emitInit(init, emitInit);
   510	  }
   511	}
