#include "EmitIR.hpp"
#include <llvm/Transforms/Utils/ModuleUtils.h>

#define self (*this)

using namespace asg;

EmitIR::EmitIR(Obj::Mgr& mgr, llvm::LLVMContext& ctx, llvm::StringRef mid)
  : mMgr(mgr)
  , mMod(mid, ctx)
  , mCtx(ctx)
  , mIntTy(llvm::Type::getInt32Ty(ctx))
  , mCurIrb(std::make_unique<llvm::IRBuilder<>>(ctx))
  , mCtorTy(llvm::FunctionType::get(llvm::Type::getVoidTy(ctx), false))
{
}

llvm::Module& EmitIR::operator()(asg::TranslationUnit* tu)
{
  for (auto&& i : tu->decls)
    self(i);
  return mMod;
}

// Type
llvm::Type* EmitIR::operator()(const Type* type)
{
  if (type->texp == nullptr) {
    switch (type->spec) {
      case Type::Spec::kInt: return llvm::Type::getInt32Ty(mCtx);
      case Type::Spec::kChar: return llvm::Type::getInt8Ty(mCtx);
      case Type::Spec::kVoid: return llvm::Type::getVoidTy(mCtx);
      default: ABORT();
    }
  }

  Type subt;
  subt.spec = type->spec;
  subt.qual = type->qual;
  subt.texp = type->texp->sub;

  if (auto _p = type->texp->dcst<PointerType>()) {
    return llvm::PointerType::get(mCtx, 0);
  }

  if (auto p = type->texp->dcst<ArrayType>()) {
    if (p->len == ArrayType::kUnLen)
      return llvm::PointerType::get(mCtx, 0);
    return llvm::ArrayType::get(self(&subt), p->len);
  }

  if (auto p = type->texp->dcst<FunctionType>()) {
    std::vector<llvm::Type*> pty;
    for (auto&& param : p->params)
      pty.push_back(self(param));
    return llvm::FunctionType::get(self(&subt), std::move(pty), false);
  }

  ABORT();
}

// Expressions
llvm::Value* EmitIR::operator()(Expr* obj)
{
  if (auto p = obj->dcst<IntegerLiteral>()) return self(p);
  if (auto p = obj->dcst<StringLiteral>()) return self(p);
  if (auto p = obj->dcst<DeclRefExpr>()) return self(p);
  if (auto p = obj->dcst<ParenExpr>()) return self(p);
  if (auto p = obj->dcst<UnaryExpr>()) return self(p);
  if (auto p = obj->dcst<BinaryExpr>()) return self(p);
  if (auto p = obj->dcst<CallExpr>()) return self(p);
  if (auto p = obj->dcst<ImplicitInitExpr>()) return nullptr;
  if (auto p = obj->dcst<ImplicitCastExpr>()) return self(p);
  ABORT();
}

llvm::Constant* EmitIR::operator()(IntegerLiteral* obj)
{
  return llvm::ConstantInt::get(self(obj->type), obj->val);
}

llvm::Value* EmitIR::operator()(StringLiteral* obj)
{
  return llvm::ConstantDataArray::getString(mCtx, obj->val);
}

llvm::Value* EmitIR::operator()(DeclRefExpr* obj)
{
  auto decl = obj->decl;
  if (auto var = decl->dcst<VarDecl>()) {
    auto alloca = static_cast<llvm::AllocaInst*>(var->any);
    return mCurIrb->CreateLoad(self(var->type), alloca);
  }
  if (auto func = decl->dcst<FunctionDecl>()) {
    return static_cast<llvm::Function*>(func->any);
  }
  ABORT();
}

llvm::Value* EmitIR::operator()(ParenExpr* obj)
{
  return self(obj->sub);
}

llvm::Value* EmitIR::operator()(UnaryExpr* obj)
{
  auto sub = self(obj->sub);
  switch (obj->op) {
    case UnaryExpr::kPos: return sub;
    case UnaryExpr::kNeg: return mCurIrb->CreateNeg(sub);
    case UnaryExpr::kNot: return mCurIrb->CreateNot(sub);
    default: ABORT();
  }
}

llvm::Value* EmitIR::operator()(BinaryExpr* obj)
{
  auto& irb = *mCurIrb;
  switch (obj->op) {
    case BinaryExpr::kAssign: {
      auto lval = static_cast<llvm::AllocaInst*>(obj->lft->dcst<DeclRefExpr>()->decl->any);
      auto rval = self(obj->rht);
      mCurIrb->CreateStore(rval, lval);
      return rval;
    }
    case BinaryExpr::kAdd: return mCurIrb->CreateAdd(self(obj->lft), self(obj->rht));
    case BinaryExpr::kSub: return mCurIrb->CreateSub(self(obj->lft), self(obj->rht));
    case BinaryExpr::kMul: return mCurIrb->CreateMul(self(obj->lft), self(obj->rht));
    case BinaryExpr::kDiv: return mCurIrb->CreateSDiv(self(obj->lft), self(obj->rht));
    case BinaryExpr::kMod: return mCurIrb->CreateSRem(self(obj->lft), self(obj->rht));
    case BinaryExpr::kGt: return mCurIrb->CreateZExt(mCurIrb->CreateICmpSGT(self(obj->lft), self(obj->rht)), mIntTy);
    case BinaryExpr::kLt: return mCurIrb->CreateZExt(mCurIrb->CreateICmpSLT(self(obj->lft), self(obj->rht)), mIntTy);
    case BinaryExpr::kGe: return mCurIrb->CreateZExt(mCurIrb->CreateICmpSGE(self(obj->lft), self(obj->rht)), mIntTy);
    case BinaryExpr::kLe: return mCurIrb->CreateZExt(mCurIrb->CreateICmpSLE(self(obj->lft), self(obj->rht)), mIntTy);
    case BinaryExpr::kEq: return mCurIrb->CreateZExt(mCurIrb->CreateICmpEQ(self(obj->lft), self(obj->rht)), mIntTy);
    case BinaryExpr::kNe: return mCurIrb->CreateZExt(mCurIrb->CreateICmpNE(self(obj->lft), self(obj->rht)), mIntTy);
    case BinaryExpr::kAnd: return mCurIrb->CreateAnd(self(obj->lft), self(obj->rht));
    case BinaryExpr::kOr: return mCurIrb->CreateOr(self(obj->lft), self(obj->rht));
    case BinaryExpr::kIndex: {
      auto ptr = self(obj->lft); // ptr to array
      auto idx = self(obj->rht);
      auto gep = mCurIrb->CreateGEP(ptr->getType(), ptr, idx);
      return mCurIrb->CreateLoad(mIntTy, gep);
    }
    default: ABORT();
  }
}

llvm::Value* EmitIR::operator()(CallExpr* obj)
{
  auto callee = self(obj->head);
  std::vector<llvm::Value*> args;
  for (auto&& arg : obj->args)
    args.push_back(self(arg));
  return mCurIrb->CreateCall(static_cast<llvm::Function*>(callee), args);
}

llvm::Value* EmitIR::operator()(InitListExpr* obj)
{
  return nullptr;
}

llvm::Value* EmitIR::operator()(ImplicitCastExpr* obj)
{
  return self(obj->sub);
}

// Statements
void EmitIR::operator()(Stmt* obj)
{
  if (auto p = obj->dcst<NullStmt>()) return self(p);
  if (auto p = obj->dcst<CompoundStmt>()) return self(p);
  if (auto p = obj->dcst<DeclStmt>()) return self(p);
  if (auto p = obj->dcst<ExprStmt>()) return self(p);
  if (auto p = obj->dcst<IfStmt>()) return self(p);
  if (auto p = obj->dcst<WhileStmt>()) return self(p);
  if (auto p = obj->dcst<DoStmt>()) return self(p);
  if (auto p = obj->dcst<BreakStmt>()) return self(p);
  if (auto p = obj->dcst<ContinueStmt>()) return self(p);
  if (auto p = obj->dcst<ReturnStmt>()) return self(p);
  ABORT();
}

void EmitIR::operator()(NullStmt* obj) {}

void EmitIR::operator()(CompoundStmt* obj)
{
  for (auto&& stmt : obj->subs)
    self(stmt);
}

void EmitIR::operator()(DeclStmt* obj)
{
  for (auto&& decl : obj->decls)
    self(decl);
}

void EmitIR::operator()(ExprStmt* obj)
{
  if (obj->expr) self(obj->expr);
}

void EmitIR::operator()(IfStmt* obj)
{
  auto& irb = *mCurIrb;
  auto cond = mCurIrb->CreateICmpNE(self(obj->cond), llvm::ConstantInt::get(mIntTy, 0));
  auto thenBb = llvm::BasicBlock::Create(mCtx, "then", mCurFunc);
  auto elseBb = llvm::BasicBlock::Create(mCtx, "else", mCurFunc);
  auto mergeBb = llvm::BasicBlock::Create(mCtx, "ifcont", mCurFunc);

  mCurIrb->CreateCondBr(cond, thenBb, obj->else_ ? elseBb : mergeBb);

  mCurIrb->SetInsertPoint(thenBb);
  self(obj->then);
  mCurIrb->CreateBr(mergeBb);

  if (obj->else_) {
    mCurIrb->SetInsertPoint(elseBb);
    self(obj->else_);
    mCurIrb->CreateBr(mergeBb);
  }

  mCurIrb->SetInsertPoint(mergeBb);
}

void EmitIR::operator()(WhileStmt* obj)
{
  auto& irb = *mCurIrb;
  auto condBb = llvm::BasicBlock::Create(mCtx, "while.cond", mCurFunc);
  auto bodyBb = llvm::BasicBlock::Create(mCtx, "while.body", mCurFunc);
  auto endBb = llvm::BasicBlock::Create(mCtx, "while.end", mCurFunc);

  mCurIrb->CreateBr(condBb);
  mCurIrb->SetInsertPoint(condBb);
  auto cond = mCurIrb->CreateICmpNE(self(obj->cond), llvm::ConstantInt::get(mIntTy, 0));
  mCurIrb->CreateCondBr(cond, bodyBb, endBb);

  mCurIrb->SetInsertPoint(bodyBb);
  self(obj->body);
  mCurIrb->CreateBr(condBb);

  mCurIrb->SetInsertPoint(endBb);
}

void EmitIR::operator()(DoStmt* obj)
{
  auto& irb = *mCurIrb;
  auto bodyBb = llvm::BasicBlock::Create(mCtx, "do.body", mCurFunc);
  auto condBb = llvm::BasicBlock::Create(mCtx, "do.cond", mCurFunc);
  auto endBb = llvm::BasicBlock::Create(mCtx, "do.end", mCurFunc);

  mCurIrb->CreateBr(bodyBb);
  mCurIrb->SetInsertPoint(bodyBb);
  self(obj->body);
  mCurIrb->CreateBr(condBb);

  mCurIrb->SetInsertPoint(condBb);
  auto cond = mCurIrb->CreateICmpNE(self(obj->cond), llvm::ConstantInt::get(mIntTy, 0));
  mCurIrb->CreateCondBr(cond, bodyBb, endBb);

  mCurIrb->SetInsertPoint(endBb);
}

void EmitIR::operator()(BreakStmt* obj) {}

void EmitIR::operator()(ContinueStmt* obj) {}

void EmitIR::operator()(ReturnStmt* obj)
{
  auto& irb = *mCurIrb;

  llvm::Value* retVal;
  if (!obj->expr)
    retVal = nullptr;
  else
    retVal = self(obj->expr);

  mCurIrb->CreateRet(retVal);

  auto exitBb = llvm::BasicBlock::Create(mCtx, "return_exit", mCurFunc);
  mCurIrb->SetInsertPoint(exitBb);
}

// Declarations
void EmitIR::operator()(Decl* obj)
{
  if (auto p = obj->dcst<VarDecl>()) return self(p);
  if (auto p = obj->dcst<FunctionDecl>()) return self(p);
  ABORT();
}

void EmitIR::operator()(VarDecl* obj)
{
  if (obj->type->spec == Type::Spec::kVoid) return;

  if (mCurFunc == nullptr) {
    // Global variable
    auto initVal = obj->init ? llvm::dyn_cast<llvm::Constant>(self(obj->init)) : nullptr;
    auto gv = new llvm::GlobalVariable(
      mMod, self(obj->type), false, llvm::GlobalValue::InternalLinkage,
      initVal ? initVal : llvm::ConstantInt::get(self(obj->type), 0), obj->name);
    obj->any = gv;
    return;
  }

  // Local variable
  auto alloca = mCurIrb->CreateAlloca(self(obj->type), nullptr, obj->name);
  obj->any = alloca;

  if (obj->init)
    mCurIrb->CreateStore(self(obj->init), alloca);
}

void EmitIR::operator()(FunctionDecl* obj)
{
  auto fty = llvm::dyn_cast<llvm::FunctionType>(self(obj->type));
  auto func = llvm::Function::Create(
    fty, llvm::GlobalVariable::ExternalLinkage, obj->name, mMod);

  obj->any = func;

  if (obj->body == nullptr)
    return;
  auto entryBb = llvm::BasicBlock::Create(mCtx, "entry", func);
  mCurIrb->SetInsertPoint(entryBb);
  auto& entryIrb = *mCurIrb;

  // Allocate and store parameters
  for (auto& arg : func->args()) {
    auto alloca = entryIrb.CreateAlloca(arg.getType(), nullptr, arg.getName());
    entryIrb.CreateStore(&arg, alloca);
  }

  mCurFunc = func;
  self(obj->body);
  auto& exitIrb = *mCurIrb;

  if (fty->getReturnType()->isVoidTy())
    exitIrb.CreateRetVoid();
  else
    exitIrb.CreateUnreachable();
}

