llvm::Value* EmitIR::operator()(BinaryExpr* obj)
{
  auto& irb = *mCurIrb;
  switch (obj->op) {
    case BinaryExpr::kAssign: {
      auto lval = static_cast<llvm::AllocaInst*>(obj->lft->dcst<DeclRefExpr>()->decl->any);
      auto rval = self(obj->rht);
