    case BinaryExpr::kDiv: return mCurIrb->CreateSDiv(self(obj->lft), self(obj->rht));
    case BinaryExpr::kMod: return mCurIrb->CreateSRem(self(obj->lft), self(obj->rht));
    case BinaryExpr::kGt: return mCurIrb->CreateZExt(mCurIrb->CreateICmpSGT(self(obj->lft), self(obj->rht)), mIntTy);
