   448	static bool
   449	promoteMemoryToRegister(Function& F, DominatorTree& DT)
   450	{
   451	  std::vector<AllocaInst*> Allocas;
   452	  BasicBlock& BB = F.getEntryBlock(); // Get the entry node for the function
   453	  bool Changed = false;
   454	
   455	  while (true) {
   456	    Allocas.clear();
   457	
   458	    // Find allocas that are safe to promote, by looking at all instructions in
   459	    // the entry node
   460	    for (BasicBlock::iterator I = BB.begin(), E = --BB.end(); I != E; ++I)
   461	      if (AllocaInst* AI = dyn_cast<AllocaInst>(I)) // Is it an alloca?
   462	        if (isAllocaPromotable(AI))
   463	          Allocas.push_back(AI);
   464	
   465	    if (Allocas.empty())
   466	      break;
   467	
   468	    PromoteMemToReg(Allocas, DT);
   469	    Changed = true;
   470	  }
   471	  return Changed;
   472	}
